  // @scenario TS-UI-018 (covers VAL-004)
  test.fixme('should disable status buttons when user lacks permission', async ({ mainPage }) => {
    await waitForAppReady(mainPage);

    // Navigate to inventory
    await mainPage.getByRole('menuitem', { name: /Tools/i }).click();
    await mainPage.getByRole('menuitem', { name: /Checking inventories/i }).hover();
    await mainPage.getByRole('menuitem', { name: /Unmatched pairs of punctuation/i }).click();

    await expect(
      mainPage.locator('.dock-tab', { hasText: /Unmatched Pairs of Punctuation/i }),
    ).toBeVisible({ timeout: 15_000 });

    const frame = mainPage.frameLocator('iframe[title="Unmatched Pairs of Punctuation Inventory"]');

    // If user is Observer (canMakeChanges=false), verify buttons disabled
    // Note: This test assumes there's a way to switch to Observer mode or test with read-only project

    const approvedButton = frame.locator('thead').getByRole('button', { name: /Approved/i });
    const unapprovedButton = frame.locator('thead').getByRole('button', { name: /Unapproved/i });
    const unknownButton = frame.locator('thead').getByRole('button', { name: /Unknown/i });

    // Verify buttons are disabled
    await expect(approvedButton).toBeDisabled();
    await expect(unapprovedButton).toBeDisabled();
    await expect(unknownButton).toBeDisabled();

    // Verify keyboard shortcuts do nothing
    const inventoryList = frame.getByTestId('inventory-list');
    const firstRow = inventoryList.locator('[role="row"]').first();
    await firstRow.click();

    await mainPage.keyboard.press('Control+Y');

    // Status should not change
    await expect(firstRow.locator('[aria-label*="Approved"]')).not.toBeVisible();
  });

